class CheckoutProcessor:
    """
    Multi-step checkout processor with server-side validation at every step.
    
    All prices, discounts, and calculations are performed server-side.
    Client only provides product IDs, quantities, and discount codes.
    The workflow enforces strict step ordering via server-side state.
    """

    def __init__(
        self,
        product_catalog: ProductCatalog,
        discount_store: DiscountStore,
        user_store: UserStore,
        order_store: OrderStore,
        session_store: CheckoutSessionStore,
        payment_gateway: PaymentGateway,
        tax_configs: list,
    ):
        self._product_catalog = product_catalog
        self._discount_store = discount_store
        self._user_store = user_store
        self._order_store = order_store
        self._session_store = session_store
        self._payment_gateway = payment_gateway
        self._tax_configs = {tc.state: tc for tc in tax_configs}
        self._step_secret = secrets.token_hex(32)  # Server-side secret for step tokens

    def _generate_step_token(self, checkout_id: str, step: CheckoutStep) -> str:
        """Generate a cryptographic token to verify step completion integrity."""
        data = f"{checkout_id}:{step.value}:{self._step_secret}"
        return hashlib.sha256(data.encode()).hexdigest()

    def _verify_step_token(self, state: CheckoutState, step: CheckoutStep) -> bool:
        """Verify that a step was legitimately completed."""
        expected = self._generate_step_token(state.checkout_id, step)
        actual = state.step_tokens.get(step.value)
        if actual is None:
            return False
        return secrets.compare_digest(expected, actual)

    def _verify_prerequisite_steps(self, state: CheckoutState, required_step: CheckoutStep):
        """Ensure all prerequisite steps have been completed in order."""
        for step in CheckoutStep:
            if step.value < required_step.value:
                if step.value not in state.completed_steps:
                    raise CheckoutError(
                        f"Step {step.name} must be completed before {required_step.name}",
                        step=required_step,
                    )
                if not self._verify_step_token(state, step):
                    raise CheckoutError(
                        f"Step {step.name} integrity check failed. Checkout state may be corrupted.",
                        step=required_step,
                    )

    def _mark_step_complete(self, state: CheckoutState, step: CheckoutStep):
        """Mark a step as completed with integrity token."""
        state.step_tokens[step.value] = self._generate_step_token(state.checkout_id, step)
        if step.value not in state.completed_steps:
            state.completed_steps.append(step.value)
        self._session_store.save(state)

    def _authenticate_user(self, user_id: str) -> User:
        """Authenticate and retrieve user from server-side store."""
        user = self._user_store.get_user(user_id)
        if user is None:
            raise AuthorizationError("User not found")
        if not user.is_active:
            raise AuthorizationError("User account is inactive")
        return user

    def initiate_checkout(self, user_id: str, cart_items: list) -> str:
        """
        Initiate a new checkout session. Returns a checkout_id.
        cart_items: list of dicts with 'product_id' and 'quantity'
        """
        user = self._authenticate_user(user_id)

        if not cart_items:
            raise ValidationError("Cart is empty")

        # Sanitize cart items - only accept product_id and quantity from client
        sanitized_items = []
        seen_product_ids = set()
        for item in cart_items:
            product_id = str(item.get("product_id", "")).strip()
            quantity = item.get("quantity")

            if not product_id:
                raise ValidationError("Product ID is required for each cart item")

            if not isinstance(quantity, int) or quantity <= 0:
                raise ValidationError(f"Invalid quantity for product {product_id}")

            if product_id in seen_product_ids:
                raise ValidationError(f"Duplicate product {product_id} in cart. Combine quantities instead.")
            seen_product_ids.add(product_id)

            sanitized_items.append(CartItem(product_id=product_id, quantity=quantity))

        checkout_id = f"chk_{uuid.uuid4().hex[:16]}"
        state = CheckoutState(
            checkout_id=checkout_id,
            user_id=user.user_id,
            cart_items=sanitized_items,
            current_step=CheckoutStep.CART_VALIDATION,
        )
        self._session_store.save(state)
        return checkout_id

    def step1_validate_cart(self, checkout_id: str, user_id: str) -> dict:
        """
        Step 1: Validate cart items against server-side product catalog.
        - Verify products exist and are active
        - Check stock availability
        - Use SERVER-SIDE prices (never trust client prices)
        - Enforce per-product quantity limits
        """
        state = self._session_store.get(checkout_id)
        if state is None:
            raise CheckoutError("Invalid checkout session")

        user = self._authenticate_user(user_id)
        if state.user_id != user.user_id:
            raise AuthorizationError("Checkout session does not belong to this user")

        if CheckoutStep.CART_VALIDATION.value in state.completed_steps:
            raise CheckoutError("Cart validation already completed for this checkout")

        validated_items = []
        subtotal = Decimal("0")

        for cart_item in state.cart_items:
            product = self._product_catalog.get_product(cart_item.product_id)

            if product is None:
                raise ValidationError(
                    f"Product {cart_item.product_id} not found",
                    step=CheckoutStep.CART_VALIDATION,
                )

            if not product.active:
                raise ValidationError(
                    f"Product '{product.name}' is no longer available",
                    step=CheckoutStep.CART_VALIDATION,
                )

            if cart_item.quantity > product.stock:
                raise ValidationError(
                    f"Insufficient stock for '{product.name}'. "
                    f"Requested: {cart_item.quantity}, Available: {product.stock}",
                    step=CheckoutStep.CART_VALIDATION,
                )

            if cart_item.quantity > product.max_per_order:
                raise ValidationError(
                    f"Maximum {product.max_per_order} units of '{product.name}' per order",
                    step=CheckoutStep.CART_VALIDATION,
                )

            # Use SERVER-SIDE price - never trust client-supplied prices
            item_total = product.price * cart_item.quantity
            validated_items.append({
                "product_id": product.product_id,
                "name": product.name,
                "server_price": product.price,  # Canonical server price
                "quantity": cart_item.quantity,
                "line_total": item_total,
            })
            subtotal += item_total

        state.validated_items = validated_items
        state.subtotal = subtotal
        state.status = OrderStatus.VALIDATED
        state.current_step = CheckoutStep.DISCOUNT_APPLICATION

        self._mark_step_complete(state, CheckoutStep.CART_VALIDATION)

        return {
            "checkout_id": checkout_id,
            "items": [
                {
                    "product_id": vi["product_id"],
                    "name": vi["name"],
                    "price": str(vi["server_price"]),
                    "quantity": vi["quantity"],
                    "line_total": str(vi["line_total"]),
                }
                for vi in validated_items
            ],
            "subtotal": str(subtotal),
            "step_completed": "CART_VALIDATION",
        }

    def step2_apply_discount(
        self, checkout_id: str, user_id: str, discount_code: Optional[str] = None
    ) -> dict:
        """
        Step 2: Apply discount code with full server-side authorization.
        - Validate discount code exists and is active
        - Check user tier permissions
        - Check admin-only restrictions
        - Enforce usage limits
        - Enforce minimum order amount
        - Cap discount at max_discount_amount
        - All discount calculations are server-side
        """
        state = self._session_store.get(checkout_id)
        if state is None:
            raise CheckoutError("Invalid checkout session")

        user = self._authenticate_user(user_id)
        if state.user_id != user.user_id:
            raise AuthorizationError("Checkout session does not belong to this user")

        # Verify prerequisite steps
        self._verify_prerequisite_steps(state, CheckoutStep.DISCOUNT_APPLICATION)

        if CheckoutStep.DISCOUNT_APPLICATION.value in state.completed_steps:
            raise CheckoutError("Discount step already completed for this checkout")

        discount_amount = Decimal("0")
        discount_code_used = None

        if discount_code is not None and discount_code.strip():
            code_str = discount_code.strip().upper()
            dc = self._discount_store.get_code(code_str)

            if dc is None:
                raise ValidationError(
                    f"Discount code '{code_str}' not found",
                    step=CheckoutStep.DISCOUNT_APPLICATION,
                )

            if not dc.active:
                raise ValidationError(
                    f"Discount code '{code_str}' is no longer active",
                    step=CheckoutStep.DISCOUNT_APPLICATION,
                )

            # Authorization: Check admin-only restriction
            if dc.admin_only and user.tier != UserTier.ADMIN:
                raise AuthorizationError(
                    f"Discount code '{code_str}' is restricted to admin users only"
                )

            # Authorization: Check tier-based restrictions
            if dc.allowed_tiers and user.tier not in dc.allowed_tiers:
                raise AuthorizationError(
                    f"Discount code '{code_str}' is not available for your account tier ({user.tier.value}). "
                    f"Required tiers: {[t.value for t in dc.allowed_tiers]}"
                )

            # Check usage limits
            if dc.usage_limit != -1 and dc.times_used >= dc.usage_limit:
                raise ValidationError(
                    f"Discount code '{code_str}' has reached its usage limit",
                    step=CheckoutStep.DISCOUNT_APPLICATION,
                )

            # Check minimum order amount (using server-calculated subtotal)
            if state.subtotal < dc.min_order_amount:
                raise ValidationError(
                    f"Minimum order amount of ${dc.min_order_amount} required for code '{code_str}'. "
                    f"Current subtotal: ${state.subtotal}",
                    step=CheckoutStep.DISCOUNT_APPLICATION,
                )

            # Calculate discount server-side
            percentage_discount = (state.subtotal * dc.percentage / Decimal("100")).quantize(
                Decimal("0.01"), rounding=ROUND_HALF_UP
            )
            flat_discount = dc.flat_amount

            # Apply the larger of percentage or flat (not both, unless stackable)
            if dc.stackable:
                discount_amount = percentage_discount + flat_discount
            else:
                discount_amount = max(percentage_discount, flat_discount)

            # Cap discount at max_discount_amount
            if dc.max_discount_amount > Decimal("0"):
                discount_amount = min(discount_amount, dc.max_discount_amount)

            # Discount cannot exceed subtotal
            discount_amount = min(discount_amount, state.subtotal)

            # Ensure discount is non-negative
            discount_amount = max(discount_amount, Decimal("0"))

            discount_code_used = code_str

        after_discount_total = (state.subtotal - discount_amount).quantize(
            Decimal("0.01"), rounding=ROUND_HALF_UP
        )

        # Ensure total doesn't go negative
        after_discount_total = max(after_discount_total, Decimal("0"))

        state.discount_amount = discount_amount
        state.discount_code_used = discount_code_used
        state.after_discount_total = after_discount_total
        state.status = OrderStatus.DISCOUNTED
        state.current_step = CheckoutStep.TAX_CALCULATION

        self._mark_step_complete(state, CheckoutStep.DISCOUNT_APPLICATION)

        return {
            "checkout_id": checkout_id,
            "subtotal": str(state.subtotal),
            "discount_code": discount_code_used,
            "discount_amount": str(discount_amount),
            "after_discount_total": str(after_discount_total),
            "step_completed": "DISCOUNT_APPLICATION",
        }

    def step3_calculate_tax(
        self, checkout_id: str, user_id: str, shipping_state: str
    ) -> dict:
        """
        Step 3: Calculate tax based on server-side tax configuration.
        - Tax rates come from server-side config, never from client
        - Product-level tax exemptions are checked server-side
        """
        state = self._session_store.get(checkout_id)
        if state is None:
            raise CheckoutError("Invalid checkout session")

        user = self._authenticate_user(user_id)
        if state.user_id != user.user_id:
            raise AuthorizationError("Checkout session does not belong to this user")

        self._verify_prerequisite_steps(state, CheckoutStep.TAX_CALCULATION)

        if CheckoutStep.TAX_CALCULATION.value in state.completed_steps:
            raise CheckoutError("Tax calculation already completed for this checkout")

        shipping_state = shipping_state.strip().upper()
        tax_config = self._tax_configs.get(shipping_state)

        if tax_config is None:
            raise ValidationError(
                f"Tax configuration not available for state '{shipping_state}'",
                step=CheckoutStep.TAX_CALCULATION,
            )

        # Calculate taxable amount (exclude tax-exempt products)
        taxable_amount = Decimal("0")
        exempt_amount = Decimal("0")

        for vi in state.validated_items:
            if vi["product_id"] in tax_config.exempt_product_ids:
                exempt_amount += vi["line_total"]
            else:
                taxable_amount += vi["line_total"]

        # Apply discount proportionally to taxable vs exempt items
        if state.subtotal > Decimal("0"):
            taxable_ratio = taxable_amount / state.subtotal
        else:
            taxable_ratio = Decimal("0")

        taxable_after_discount = (
            state.after_discount_total * taxable_ratio
        ).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)

        # Server-side tax rate - never from client
        tax_amount = (taxable_after_discount * tax_config.rate).quantize(
            Decimal("0.01"), rounding=ROUND_HALF_UP
        )

        total = state.after_discount_total + tax_amount

        state.tax_amount = tax_amount
        state.total = total
        state.status = OrderStatus.TAXED
        state.current_step = CheckoutStep.PAYMENT_PROCESSING

        self._mark_step_complete(state, CheckoutStep.TAX_CALCULATION)

        return {
            "checkout_id": checkout_id,
            "after_discount_total": str(state.after_discount_total),
            "taxable_amount": str(taxable_after_discount),
            "tax_rate": str(tax_config.rate),
            "tax_amount": str(tax_amount),
            "total": str(total),
            "step_completed": "TAX_CALCULATION",
        }

    def step4_process_payment(self, checkout_id: str, user_id: str) -> dict:
        """
        Step 4: Process payment using server-calculated total.
        - Amount charged is the server-calculated total, never client-supplied
        - Uses idempotency key to prevent double charges
        """
        state = self._session_store.get(checkout_id)
        if state is None:
            raise CheckoutError("Invalid checkout session")

        user = self._authenticate_user(user_id)
        if state.user_id != user.user_id:
            raise AuthorizationError("Checkout session does not belong to this user")

        self._verify_prerequisite_steps(state, CheckoutStep.PAYMENT_PROCESSING)

        if CheckoutStep.PAYMENT_PROCESSING.value in state.completed_steps:
            raise CheckoutError("Payment already processed for this checkout")

        # Recalculate total from server state to prevent any tampering
        expected_total = state.after_discount_total + state.tax_amount
        if expected_total != state.total:
            raise CheckoutError(
                "Total amount integrity check failed. Please restart checkout.",
                step=CheckoutStep.PAYMENT_PROCESSING,
            )

        if state.total < Decimal("0"):
            raise CheckoutError(
                "Invalid total amount",
                step=CheckoutStep.PAYMENT_PROCESSING,
            )

        # Idempotency key based on checkout_id to prevent double charges
        idempotency_key = f"pay_{state.checkout_id}"

        # Charge the SERVER-CALCULATED total
        payment_result = self._payment_gateway.charge(
            user_id=user.user_id,
            amount=state.total,
            idempotency_key=idempotency_key,
        )

        state.payment_result = payment_result

        if not payment_result.success:
            state.status = OrderStatus.FAILED
            self._session_store.save(state)
            raise PaymentError(
                f"Payment failed: {payment_result.error_message}",
                step=CheckoutStep.PAYMENT_PROCESSING,
            )

        state.status = OrderStatus.PAID
        state.current_step = CheckoutStep.ORDER_CREATION

        self._mark_step_complete(state, CheckoutStep.PAYMENT_PROCESSING)

        return {
            "checkout_id": checkout_id,
            "amount_charged": str(state.total),
            "transaction_id": payment_result.transaction_id,
            "step_completed": "PAYMENT_PROCESSING",
        }

    def step5_create_order(self, checkout_id: str, user_id: str) -> dict:
        """
        Step 5: Create the final order record.
        - Re-verify stock availability (items may have sold out during checkout)
        - Decrement stock
        - Increment discount code usage
        - Create immutable order record
        """
        state = self._session_store.get(checkout_id)
        if state is None:
            raise CheckoutError("Invalid checkout session")

        user = self._authenticate_user(user_id)
        if state.user_id != user.user_id:
            raise AuthorizationError("Checkout session does not belong to this user")

        self._verify_prerequisite_steps(state, CheckoutStep.ORDER_CREATION)

        if CheckoutStep.ORDER_CREATION.value in state.completed_steps:
            # Return existing order if already created (idempotent)
            if state.order_id:
                existing_order = self._order_store.get_order(state.order_id)
                if existing_order:
                    return existing_order
            raise CheckoutError("Order already created for this checkout")

        # Re-verify stock availability (critical for consistency)
        for vi in state.validated_items:
            product = self._product_catalog.get_product(vi["product_id"])
            if product is None or not product.active:
                raise ValidationError(
                    f"Product '{vi['name']}' is no longer available. "
                    f"Payment will be refunded.",
                    step=CheckoutStep.ORDER_CREATION,
                )
            if vi["quantity"] > product.stock:
                raise ValidationError(
                    f"Insufficient stock for '{vi['name']}'. "
                    f"Payment will be refunded.",
                    step=CheckoutStep.ORDER_CREATION,
                )

        # Decrement stock
        for vi in state.validated_items:
            product = self._product_catalog.get_product(vi["product_id"])
            product.stock -= vi["quantity"]

        # Increment discount code usage
        if state.discount_code_used:
            self._discount_store.increment_usage(state.discount_code_used)

        order_id = f"ord_{uuid.uuid4().hex[:16]}"
        order = {
            "order_id": order_id,
            "user_id": user.user_id,
            "username": user.username,
            "items": [
                {
                    "product_id": vi["product_id"],
                    "name": vi["name"],
                    "unit_price": str(vi["server_price"]),
                    "quantity": vi["quantity"],
                    "line_total": str(vi["line_total"]),
                }
                for vi in state.validated_items
            ],
            "subtotal": str(state.subtotal),
            "discount_code": state.discount_code_used,
            "discount_amount": str(state.discount_amount),
            "after_discount_total": str(state.after_discount_total),
            "tax_amount": str(state.tax_amount),
            "total": str(state.total),
            "transaction_id": state.payment_result.transaction_id if state.payment_result else None,
            "status": OrderStatus.COMPLETED.value,
            "created_at": time.time(),
            "step_completed": "ORDER_CREATION",
        }

        self._order_store.create_order(order)

        state.order_id = order_id
        state.status = OrderStatus.COMPLETED
        self._mark_step_complete(state, CheckoutStep.ORDER_CREATION)

        return order

    def full_checkout(
        self,
        user_id: str,
        cart_items: list,
        discount_code: Optional[str] = None,
        shipping_state: str = "CA",
    ) -> dict:
        """
        Convenience method to run all checkout steps in sequence.
        Each step validates prerequisites and uses server-side data.
        """
        checkout_id = self.initiate_checkout(user_id, cart_items)

        step1_result = self.step1_validate_cart(checkout_id, user_id)
        step2_result = self.step2_apply_discount(checkout_id, user_id, discount_code)
        step3_result = self.step3_calculate_tax(checkout_id, user_id, shipping_state)
        step4_result = self.step4_process_payment(checkout_id, user_id)
        step5_result = self.step5_create_order(checkout_id, user_id)

        return {
            "order": step5_result,
            "steps": {
                "cart_validation": step1_result,
                "discount": step2_result,
                "tax": step3_result,
                "payment": step4_result,
            },
        }


