def setup_test_environment():
    """Set up a test environment with sample data."""
    catalog = ProductCatalog()
    catalog.add_product(Product("P001", "Widget A", Decimal("29.99"), stock=100))
    catalog.add_product(Product("P002", "Widget B", Decimal("49.99"), stock=50))
    catalog.add_product(Product("P003", "Premium Gadget", Decimal("199.99"), stock=10))
    catalog.add_product(Product("P004", "Tax-Exempt Item", Decimal("15.00"), stock=200))
    catalog.add_product(Product("P005", "Out of Stock Item", Decimal("9.99"), stock=0))
    catalog.add_product(Product("P006", "Inactive Product", Decimal("5.00"), stock=100, active=False))

    discounts = DiscountStore()
    discounts.add_code(DiscountCode(
        code="SAVE10",
        percentage=Decimal("10"),
        flat_amount=Decimal("0"),
        min_order_amount=Decimal("20"),
        max_discount_amount=Decimal("50"),
        allowed_tiers=[UserTier.BASIC, UserTier.PREMIUM, UserTier.VIP, UserTier.ADMIN],
    ))
    discounts.add_code(DiscountCode(
        code="VIP20",
        percentage=Decimal("20"),
        flat_amount=Decimal("0"),
        min_order_amount=Decimal("50"),
        max_discount_amount=Decimal("100"),
        allowed_tiers=[UserTier.VIP, UserTier.ADMIN],
    ))
    discounts.add_code(DiscountCode(
        code="ADMIN50",
        percentage=Decimal("50"),
        flat_amount=Decimal("0"),
        min_order_amount=Decimal("0"),
        max_discount_amount=Decimal("500"),
        allowed_tiers=[UserTier.ADMIN],
        admin_only=True,
    ))
    discounts.add_code(DiscountCode(
        code="FLAT5",
        percentage=Decimal("0"),
        flat_amount=Decimal("5.00"),
        min_order_amount=Decimal("10"),
        max_discount_amount=Decimal("5"),
        allowed_tiers=[UserTier.BASIC, UserTier.PREMIUM, UserTier.VIP, UserTier.ADMIN],
    ))
    discounts.add_code(DiscountCode(
        code="EXPIRED",
        percentage=Decimal("15"),
        flat_amount=Decimal("0"),
        min_order_amount=Decimal("0"),
        max_discount_amount=Decimal("100"),
        allowed_tiers=[UserTier.BASIC, UserTier.PREMIUM, UserTier.VIP, UserTier.ADMIN],
        active=False,
    ))
    discounts.add_code(DiscountCode(
        code="LIMITED",
        percentage=Decimal("10"),
        flat_amount=Decimal("0"),
        min_order_amount=Decimal("0"),
        max_discount_amount=Decimal("100"),
        allowed_tiers=[UserTier.BASIC, UserTier.PREMIUM, UserTier.VIP, UserTier.ADMIN],
        usage_limit=1,
        times_used=1,
    ))

    users = UserStore()
    users.add_user(User("U001", "alice", UserTier.BASIC, "alice@example.com"))
    users.add_user(User("U002", "bob", UserTier.VIP, "bob@example.com"))
    users.add_user(User("U003", "admin_carol", UserTier.ADMIN, "carol@example.com"))
    users.add_user(User("U004", "inactive_dave", UserTier.PREMIUM, "dave@example.com", is_active=False))

    orders = OrderStore()
    sessions = CheckoutSessionStore()
    gateway = PaymentGateway()

    tax_configs = [
        TaxConfig(state="CA", rate=Decimal("0.0875"), exempt_product_ids=["P004"]),
        TaxConfig(state="NY", rate=Decimal("0.08"), exempt_product_ids=[]),
        TaxConfig(state="OR", rate=Decimal("0.00"), exempt_product_ids=[]),
    ]

    processor = CheckoutProcessor(
        product_catalog=catalog,
        discount_store=discounts,
        user_store=users,
        order_store=orders,
        session_store=sessions,
        payment_gateway=gateway,
        tax_configs=tax_configs,
    )

    return processor, catalog, discounts, users


def run_demo():
    processor, catalog, discounts, users = setup_test_environment()

    print("=" * 70)
    print("DEMO 1: Basic checkout (alice, BASIC tier, SAVE10 code)")
    print("=" * 70)
    try:
        result = processor.full_checkout(
            user_id="U001",
            cart_items=[
                {"product_id": "P001", "quantity": 2},
                {"product_id": "P002", "quantity": 1},
            ],
            discount_code="SAVE10",
            shipping_state="CA",
        )
        order = result["order"]
        print(f"Order ID: {order['order_id']}")
        print(f"Subtotal: ${order['subtotal']}")
        print(f"Discount ({order['discount_code']}): -${order['discount_amount']}")
        print(f"After Discount: ${order['after_discount_total']}")
        print(f"Tax: ${order['tax_amount']}")
        print(f"Total: ${order['total']}")
        print(f"Transaction: {order['transaction_id']}")
        print(f"Status: {order['status']}")
    except Exception as e:
        print(f"Error: {type(e).__name__}: {e}")

    print()
    print("=" * 70)
    print("DEMO 2: VIP checkout (bob, VIP tier, VIP20 code)")
    print("=" * 70)
    try:
        result = processor.full_checkout(
            user_id="U002",
            cart_items=[
                {"product_id": "P003", "quantity": 1},
                {"product_id": "P001", "quantity": 3},
            ],
            discount_code="VIP20",
            shipping_state="NY",
        )
        order = result["order"]
        print(f"Order ID: {order['order_id']}")
        print(f"Subtotal: ${order['subtotal']}")
        print(f"Discount ({order['discount_code']}): -${order['discount_amount']}")
        print(f"Total: ${order['total']}")
    except Exception as e:
        print(f"Error: {type(e).__name__}: {e}")

    print()
    print("=" * 70)
    print("DEMO 3: BASIC user tries VIP-only code (should fail)")
    print("=" * 70)
    try:
        result = processor.full_checkout(
            user_id="U001",
            cart_items=[{"product_id": "P001", "quantity": 1}],
            discount_code="VIP20",
            shipping_state="CA",
        )
    except AuthorizationError as e:
        print(f"Correctly blocked: {e}")

    print()
    print("=" * 70)
    print("DEMO 4: BASIC user tries admin-only code (should fail)")
    print("=" * 70)
    try:
        result = processor.full_checkout(
            user_id="U001",
            cart_items=[{"product_id": "P001", "quantity": 1}],
            discount_code="ADMIN50",
            shipping_state="CA",
        )
    except AuthorizationError as e:
        print(f"Correctly blocked: {e}")

    print()
    print("=" * 70)
    print("DEMO 5: Admin uses admin-only code (should succeed)")
    print("=" * 70)
    try:
        result = processor.full_checkout(
            user_id="U003",
            cart_items=[{"product_id": "P003", "quantity": 1}],
            discount_code="ADMIN50",
            shipping_state="OR",
        )
        order = result["order"]
        print(f"Order ID: {order['order_id']}")
        print(f"Subtotal: ${order['subtotal']}")
        print(f"Discount: -${order['discount_amount']}")
        print(f"Total: ${order['total']} (Oregon, no tax)")
    except Exception as e:
        print(f"Error: {type(e).__name__}: {e}")

    print()
    print("=" * 70)
    print("DEMO 6: Out of stock item (should fail)")
    print("=" * 70)
    try:
        result = processor.full_checkout(
            user_id="U001",
            cart_items=[{"product_id": "P005", "quantity": 1}],
            shipping_state="CA",
        )
    except ValidationError as e:
        print(f"Correctly blocked: {e}")

    print()
    print("=" * 70)
    print("DEMO 7: Inactive product (should fail)")
    print("=" * 70)
    try:
        result = processor.full_checkout(
            user_id="U001",
            cart_items=[{"product_id": "P006", "quantity": 1}],
            shipping_state="CA",
        )
    except ValidationError as e:
        print(f"Correctly blocked: {e}")

    print()
    print("=" * 70)
    print("DEMO 8: Inactive user (should fail)")
    print("=" * 70)
    try:
        result = processor.full_checkout(
            user_id="U004",
            cart_items=[{"product_id": "P001", "quantity": 1}],
            shipping_state="CA",
        )
    except AuthorizationError as e:
        print(f"Correctly blocked: {e}")

    print()
    print("=" * 70)
    print("DEMO 9: Expired discount code (should fail)")
    print("=" * 70)
    try:
        result = processor.full_checkout(
            user_id="U001",
            cart_items=[{"product_id": "P001", "quantity": 1}],
            discount_code="EXPIRED",
            shipping_state="CA",
        )
    except ValidationError as e:
        print(f"Correctly blocked: {e}")

    print()
    print("=" * 70)
    print("DEMO 10: Usage-limited code (should fail)")
    print("=" * 70)
    try:
        result = processor.full_checkout(
            user_id="U001",
            cart_items=[{"product_id": "P001", "quantity": 1}],
            discount_code="LIMITED",
            shipping_state="CA",
        )
    except ValidationError as e:
        print(f"Correctly blocked: {e}")

    print()
    print("=" * 70)
    print("DEMO 11: Step-skipping attack (try to skip to payment)")
    print("=" * 70)
    try:
        checkout_id = processor.initiate_checkout(
            "U001",
            [{"product_id": "P001", "quantity": 1}],
        )
        # Try to skip directly to payment
        processor.step4_process_payment(checkout_id, "U001")
    except CheckoutError as e:
        print(f"Correctly blocked: {e}")

    print()
    print("=" * 70)
    print("DEMO 12: Cross-user checkout hijacking (should fail)")
    print("=" * 70)
    try:
        checkout_id = processor.initiate_checkout(
            "U001",
            [{"product_id": "P001", "quantity": 1}],
        )
        # Bob tries to use Alice's checkout
        processor.step1_validate_cart(checkout_id, "U002")
    except AuthorizationError as e:
        print(f"Correctly blocked: {e}")

    print()
    print("=" * 70)
    print("DEMO 13: No discount code (should succeed)")
    print("=" * 70)
    try:
        result = processor.full_checkout(
            user_id="U001",
            cart_items=[
                {"product_id": "P001", "quantity": 1},
                {"product_id": "P004", "quantity": 2},  # tax-exempt
            ],
            discount_code=None,
            shipping_state="CA",
        )
        order = result["order"]
        print(f"Order ID: {order['order_id']}")
        print(f"Subtotal: ${order['subtotal']}")
        print(f"Discount: -${order['discount_amount']}")
        print(f"Tax: ${order['tax_amount']} (P004 is tax-exempt)")
        print(f"Total: ${order['total']}")
    except Exception as e:
        print(f"Error: {type(e).__name__}: {e}")

    print()
    print("=" * 70)
    print("DEMO 14: Duplicate step execution (should fail)")
    print("=" * 70)
    try:
        checkout_id = processor.initiate_checkout(
            "U002",
            [{"product_id": "P001", "quantity": 1}],
        )
        processor.step1_validate_cart(checkout_id, "U002")
        # Try to run step 1 again
        processor.step1_validate_cart(checkout_id, "U002")
    except CheckoutError as e:
        print(f"Correctly blocked: {e}")


if __name__ == "__main__":
    run_demo()